13	// TestWorkerDispatchAdapterEmptyArgsDefaultsProfile pins ddx-755f5881 AC #1:
14	// workerDispatchAdapter.DispatchWorker with an empty rawArgs and no
15	// workers.default_spec must produce a spec with Profile: "default" and no
16	// other knobs set. This is the contract that eliminates the historical
17	// 19-burn drain-queue failure mode where an empty input fanned out into
18	// per-tier ladder iteration with no upstream synthesis target.
19	func TestWorkerDispatchAdapterEmptyArgsDefaultsProfile(t *testing.T) {
20		root := t.TempDir()
21		setupBeadStore(t, root)
22	
23		// Bare config — no workers block, no agent.routing block.
24		cfg := "version: \"1.0\"\nlibrary:\n  path: \".ddx/plugins/ddx\"\n  repository:\n    url: \"https://example.com/lib\"\n    branch: \"main\"\n"
25		if err := writeFile(filepath.Join(root, ".ddx", "config.yaml"), cfg); err != nil {
26			t.Fatal(err)
27		}
28	
29		m := NewWorkerManager(root)
30		defer m.StopWatchdog()
31		// Stub out the bead worker so StartExecuteLoop does not require a real
32		// agent service. The executor blocks until ctx is cancelled (Stop below).
33		m.BeadWorkerFactory = func(s agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
34			return &agent.ExecuteBeadWorker{
35				Store: s,
36				Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
37					<-ctx.Done()
38					return agent.ExecuteBeadReport{BeadID: beadID, Status: agent.ExecuteBeadStatusExecutionFailed, Detail: "canceled"}, ctx.Err()
39				}),
40			}
41		}
42	
43		adapter := &workerDispatchAdapter{manager: m}
44		result, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
