96	// TestWorkerDispatchAdapterHistoricalDrainConfigNoSynthesis pins ddx-755f5881
97	// AC #4: the same historical drain-queue config (with agent.routing
98	// profile_ladders + model_overrides) that previously caused the 19-burn
99	// failure mode must no longer drive DDx-side synthesis on the default
100	// dispatch path. The deprecated routing fields are NOT consulted; the
101	// dispatched spec is just {Profile: "default"}, so a downstream worker
102	// either succeeds or returns a single typed error — it can no longer fan
103	// out into per-tier iteration with mismatched harness+model pairs.
104	func TestWorkerDispatchAdapterHistoricalDrainConfigNoSynthesis(t *testing.T) {
105		root := t.TempDir()
106		setupBeadStore(t, root)
107	
108		// Mirror the shape of the user's historical config: routing block with
109		// profile_ladders and model_overrides naming a model that previously
110		// triggered the gemini+minimax misroute fan-out.
111		cfg := `version: "1.0"
112	library:
113	  path: ".ddx/plugins/ddx"
114	  repository:
115	    url: "https://example.com/lib"
116	    branch: "main"
117	agent:
118	  routing:
119	    profile_ladders:
120	      default: [cheap, standard, smart]
121	    model_overrides:
122	      cheap: minimax/minimax-m2.7
123	`
124		if err := writeFile(filepath.Join(root, ".ddx", "config.yaml"), cfg); err != nil {
125			t.Fatal(err)
126		}
127	
128		m := NewWorkerManager(root)
129		defer m.StopWatchdog()
130		m.BeadWorkerFactory = func(s agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
131			return &agent.ExecuteBeadWorker{
132				Store: s,
133				Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
134					<-ctx.Done()
135					return agent.ExecuteBeadReport{BeadID: beadID, Status: agent.ExecuteBeadStatusExecutionFailed, Detail: "canceled"}, ctx.Err()
136				}),
137			}
138		}
139	
140		agent.ResetRoutingCallCounters()
141		adapter := &workerDispatchAdapter{manager: m}
142		result, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
143		if err != nil {
144			t.Fatalf("dispatch with historical config: %v", err)
145		}
146		defer func() { _ = m.Stop(result.ID) }()
147	
148		specBytes, err := os.ReadFile(filepath.Join(m.rootDir, result.ID, "spec.json"))
149		if err != nil {
150			t.Fatalf("read spec.json: %v", err)
151		}
152		var spec ExecuteLoopWorkerSpec
153		if err := json.Unmarshal(specBytes, &spec); err != nil {
154			t.Fatalf("unmarshal spec.json: %v", err)
155		}
156		if spec.Profile != "default" {
157			t.Errorf("Profile: want %q, got %q", "default", spec.Profile)
158		}
159		if spec.Model != "" {
160			t.Errorf("Model must be empty — historical model_overrides must NOT drive synthesis on default path, got %q", spec.Model)
161		}
162		if spec.Harness != "" {
163			t.Errorf("Harness must be empty on default path, got %q", spec.Harness)
164		}
165		// The dispatch step itself must not consult the ladder helpers.
166		if got := agent.ResolveProfileLadderCallCount(); got != 0 {
167			t.Errorf("ResolveProfileLadder must not be called on default dispatch path, got %d", got)
168		}
169		if got := agent.ResolveTierModelRefCallCount(); got != 0 {
170			t.Errorf("ResolveTierModelRef must not be called on default dispatch path, got %d", got)
171		}
172	}
